import org.owasp.encoder.Encode;

import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        String encodedUserName = Encode.forHtml(userName); // Properly encode user input

        System.out.println("Hello, " + encodedUserName + "!"); // Output encoded user input

        // Malicious script injection will be properly escaped
        System.out.println(Encode.forHtml("<script>alert('XSS Vulnerability')</script>"));
    }
}

